// Valida y normaliza el payload de actualizacion parcial.
// Solo session_id es obligatorio. Los demas campos son opcionales.
// No sobrescribe con null: si un campo no viene, no se toca.

const d = $json;

if (!d.session_id || typeof d.session_id !== 'string') {
  throw new Error('session_id requerido');
}
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!UUID_RE.test(d.session_id)) {
  throw new Error('session_id debe ser UUID valido');
}

const PLAZO_MAP = {
  'inmediato': 'ahora',
  'ahora': 'ahora',
  '1-3m': '1_a_3_meses',
  '1_a_3_meses': '1_a_3_meses',
  '3-6m': '3_a_6_meses',
  '3_a_6_meses': '3_a_6_meses',
  '6-12m': '6_a_12_meses',
  '6_a_12_meses': '6_a_12_meses',
  '12m+': 'mas_de_1_ano',
  'mas_de_1_ano': 'mas_de_1_ano',
  'no_definido': 'no_definido',
};

const USO_ENUM = new Set(['vivienda', 'segunda', 'inversion', 'no_definido']);
const FORMA_PAGO_ENUM = new Set(['contado', 'credito', 'subsidio', 'mixto', 'no_definido']);
const RANGO_ENUM = new Set(['<20M', '20-40M', '40-60M', '>60M', 'no_definido']);
const DECISOR_ENUM = new Set(['solo', 'pareja', 'familia', 'no_definido']);

const INTENCION_TO_USO = {
  'inversion': 'inversion',
  'segunda_vivienda': 'segunda',
  'vivir_permanente': 'vivienda',
  'evaluando': 'no_definido',
  'no_definido': 'no_definido',
};

const patch = {};
const fieldsUpdated = [];

if (d.nombre || d.apellido) {
  const nombreCompleto = [d.nombre, d.apellido].filter(Boolean).join(' ').trim().slice(0, 150);
  if (nombreCompleto) {
    patch.nombre = nombreCompleto;
    fieldsUpdated.push('nombre');
  }
}
if (d.whatsapp) {
  patch.whatsapp = String(d.whatsapp).slice(0, 30);
  fieldsUpdated.push('whatsapp');
}
if (d.email) {
  patch.email = String(d.email).slice(0, 120);
  fieldsUpdated.push('email');
}
if (d.plazo) {
  const norm = PLAZO_MAP[d.plazo] || 'no_definido';
  patch.plazo = norm;
  fieldsUpdated.push('plazo');
}
if (d.uso && USO_ENUM.has(d.uso)) {
  patch.uso = d.uso;
  fieldsUpdated.push('uso');
} else if (d.intencion) {
  const mapped = INTENCION_TO_USO[d.intencion];
  if (mapped) {
    patch.uso = mapped;
    patch.intencion = d.intencion;
    fieldsUpdated.push('uso', 'intencion');
  }
}
if (d.forma_pago && FORMA_PAGO_ENUM.has(d.forma_pago)) {
  patch.forma_pago = d.forma_pago;
  fieldsUpdated.push('forma_pago');
}
if (typeof d.pre_aprobacion === 'boolean') {
  patch.pre_aprobacion = d.pre_aprobacion;
  fieldsUpdated.push('pre_aprobacion');
}
if (d.decisor && DECISOR_ENUM.has(d.decisor)) {
  patch.decisor = d.decisor;
  fieldsUpdated.push('decisor');
}
if (d.rango_presupuesto && RANGO_ENUM.has(d.rango_presupuesto)) {
  patch.rango_presupuesto = d.rango_presupuesto;
  fieldsUpdated.push('rango_presupuesto');
}
if (d.resumen) {
  patch.resumen = String(d.resumen).slice(0, 800);
  fieldsUpdated.push('resumen');
}
// Parcela de interes (texto libre: numero o codigo tipo 28 o B5)
if (d.parcela_interes) {
  patch.parcela_interes = String(d.parcela_interes).slice(0, 30);
  fieldsUpdated.push('parcela_interes');
}
// Pie disponible (solo aplica si forma_pago es credito, pero aceptamos cualquier entrada)
if (d.pie_disponible) {
  patch.pie_disponible = String(d.pie_disponible).slice(0, 30);
  fieldsUpdated.push('pie_disponible');
}

if (fieldsUpdated.length === 0) {
  return [{ json: {
    session_id: d.session_id,
    patch: null,
    fields_updated: [],
    skip: true,
  } }];
}

return [{ json: {
  session_id: d.session_id,
  patch,
  fields_updated: fieldsUpdated,
  skip: false,
} }];

// Construye body final del PATCH con score_history actualizado
// y merge acumulativo para parcela_interes.
//
// Acumulativos (no pisan, agregan): parcela_interes (lista separada por comas)
// Sobrescribibles (se reemplazan): todos los demas campos.

const validated = $('Validate & Normalize').first().json;
const current = $json;

let leadId = null;
let history = [];
let currentParcela = '';
if (Array.isArray(current) && current.length > 0) {
  leadId = current[0].id;
  history = Array.isArray(current[0].score_history) ? current[0].score_history : [];
  currentParcela = current[0].parcela_interes || '';
} else if (current && current.id) {
  leadId = current.id;
  history = Array.isArray(current.score_history) ? current.score_history : [];
  currentParcela = current.parcela_interes || '';
}

if (!leadId) {
  return [{ json: {
    ok: false,
    reason: 'lead_no_existe',
    session_id: validated.session_id,
  } }];
}

// Merge acumulativo para parcela_interes.
const patch = { ...validated.patch };
const fieldsActuallyChanged = [...validated.fields_updated];

if (patch.parcela_interes) {
  const nuevos = String(patch.parcela_interes)
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);
  const existentes = currentParcela
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);
  const setExistentes = new Set(existentes.map(s => s.toLowerCase()));
  const aAgregar = nuevos.filter(n => !setExistentes.has(n.toLowerCase()));

  if (aAgregar.length === 0) {
    // La parcela ya estaba en la lista: no agrega nada.
    delete patch.parcela_interes;
    const idx = fieldsActuallyChanged.indexOf('parcela_interes');
    if (idx !== -1) fieldsActuallyChanged.splice(idx, 1);
  } else {
    const merged = [...existentes, ...aAgregar].join(', ').slice(0, 200);
    patch.parcela_interes = merged;
  }
}

const newEntry = {
  at: new Date().toISOString(),
  action: 'partial_update',
  fields_updated: fieldsActuallyChanged,
};

const body = {
  ...patch,
  score_history: [...history, newEntry],
};

return [{ json: {
  session_id: validated.session_id,
  lead_id: leadId,
  body,
  fields_updated: fieldsActuallyChanged,
} }];

const prepared = $('Build PATCH body').first().json;

if (prepared.ok === false) {
  return [{ json: { ok: false, reason: prepared.reason, session_id: prepared.session_id, tool_output_text: null } }];
}

if (prepared.skipped === true) {
  return [{ json: { ok: true, skipped: true, reason: prepared.reason, lead_id: prepared.lead_id, session_id: prepared.session_id, tool_output_text: null } }];
}

return [{ json: { ok: true, lead_id: prepared.lead_id, session_id: prepared.session_id, fields_saved: prepared.fields_updated, tool_output_text: null } }];
